.12813185,0.01094171,0.03821043,0.00159211,-0.02477625,-0.00639412,0.07085767,0.05949220,0.02086315,-0.00719086,0.01912803,-0.00108995,0.02468896,0.03060015,0.01860259,-0.03286681,-0.05923270,0.04002233,-0.03759149,0.02020534,0.02300551,-0.01522239,0.07433431,-0.00270709,-0.05591217,-0.00515623,0.03551171,-0.02401943,-0.04931776,-0.02907722,0.02158937,0.02736682,0.00047888,0.06329503,-0.00725475,0.05994281,-0.01122302,0.02492171,0.02139741,-0.06317154,0.06636225,0.02189067,0.09180042]',E'Using client-side SSL/TLS\n\n```cpp\n// Create a default SSL ChannelCredentials object.\nauto channel_creds = grpc::SslCredentials(grpc::SslCredentialsOptions());\n// Create a channel using the credentials created in the previous step.\nauto channel = grpc::CreateChannel(server_name, channel_creds);\n// Create a stub on the channel.\nstd::unique_ptr<Greeter::Stub> stub(Greeter::NewStub(channel));\n// Make actual RPC calls on the stub.\ngrpc::Status s = stub->sayHello(&context, *request, response);\n```','{"source": "grpc", "version": "1.65", "language": "proto", "title": "Auth", "section_title": "auth", "url": "https://github.com/grpc/grpc.io/blob/main/content/en/docs/guides/auth.md", "topics": "grpc,rpc,auth", "categories": "rpc,networking,proto"}');
