397408,0.03383825,0.06308056,0.03132108,-0.01639188,-0.00540108,0.03123784,0.00034261,-0.00259635,-0.09744193,0.08527775,0.04447718,0.03171674,-0.06567058,0.07119283,-0.01203746,-0.00526795,-0.05539328,-0.03019331,0.00971830,-0.00729193,0.01670366,0.06633674,0.03675252,-0.03000662,-0.05661105,0.00902673,0.01059999,-0.00147309,-0.08382655,-0.00989203,0.03044704,0.06090979,0.06985238,-0.01913087,-0.00517836,-0.08342859,0.00605258,0.02498345,-0.02259940,0.08136268,0.02001146,0.01626225]',E'RouteGuideServicer provides an implementation of the methods of the RouteGuide service.\n\n```python\ndef RecordRoute(self, request_iterator, context):\n    point_count = 0\n    feature_count = 0\n    distance = 0.0\n    prev_point = None\n\n    start_time = time.time()\n    for point in request_iterator:\n        point_count += 1\n        if get_feature(self.db, point):\n            feature_count += 1\n        if prev_point:\n            distance += get_distance(prev_point, point)\n        prev_point = point','{"source": "grpc", "version": "1.65", "language": "proto", "title": "RouteGuideServicer provides an implementation of the methods of the RouteGuide service.", "section_title": "basics", "url": "https://github.com/grpc/grpc.io/blob/main/content/en/docs/languages/python/basics.md", "topics": "grpc,rpc,basics", "categories": "rpc,networking,proto"}');
